window.__dh_data["ar"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "الداما بادا",
  "chaps": "الفصول",
  "fontsize": "حجم الخط",
  "chap1": "الثنائيات",
  "1": "أشكال الحالات الذهنية جميعها مصدرها الذهن، فهي كلها من صنعه؛ لذا فهو الذي يقودها. فإذا تكلم أحد أو قام بفعل بذهن مشوش، تبعته المعاناة Dukkha، تماماً كما تتبع العجلة آثار حافر الثور الذي يسحب العربة.",
  "2": "أشكال الحالات الذهنية جميعها مصدرها الذهن، فهي كلها من صنعه؛ لذا فهو الذي يقودها. فإذا تكلم أحد بذهن نقي تبعته الفرح والبهجة sukha، مثل الظل الذي لا يغادره.",
  "3": "لقد آذاني، لقد عاملني بسوء، لقد أخذ مني أفضل ما عندي، لقد سرق ممتلكاتي ... إلخ. لا يمكن تخفيف مشاعر الكراهية عند أولئك الذين يكونون مثل هذه الأفكار.",
  "4": "لقد آذاني، لقد عاملني بسوء، لقد أخذ مني أفضل ما عندي، لقد سرق ممتلكاتي ... إلخ. يمكن تخفيف مشاعر الكراهية عند أولئك الذين لا يكونون مثل هذه الأفكار.",
  "5": "في واقع الأمر، لا يمكن التخفيف من الكره، من خلال نشر الكره في هذا العالم، بل من خلال نشر الطيبة المحبة. وهذا قانون قديم.",
  "6": "لا يدرك الناس أن الموت محتم عليهم إلا أهل الحكمة منهم. لهذا فهم أبعد الناس بحكمتهم عن الخصومة والشقاق.",
  "7": "من كان ذهنه مشغولاً بالمتع الحسية، وكان غير منضبط في حواسه، وغير معتدل في مأكله، وكسولاً، سوف تغلبه المارا Mara حتماً، وتقتلعه كما تقتلع الرياح العاصفة الشجرة الضعيفة.",
  "8": "من يحافظ على ذهنه واعياً بالأمور المفسدة، ويكون منضبطاً في حواسه، ومعتدلاً في مأكله، متسماً بالنشاط، محافظاً على سلامة اعتقاده وتوقه، فلن تغلبه المارا، كما الجبل لا تهزه الريح العاصفة.",
  "9": "من لم يتخل عن السموم الأخلاقية أو السموم الذهنية (kilesas)، ويتشح بالرداء الأصفر (أي كان من الرهبان)، ويفتقر إلى الانضباط والالتزام، فإنه ليس أهلاً لذلك الرداء الأصفر.",
  "10": "المنضبط والملتزم بالتعاليم، الذي نبذ جميع السموم الذهنية، هو لا شك أهلاً للرداء الأصفر.",
  "11": "أصحاب النظرة الخاطئة، هم الذين لا يروْن الأمور على حقيقتها وفي جوهرها، الذين يعيشون في عالم الزيف والأفكار الخاطئة.",
  "12": "أصحاب النظرة السليمة، هم الذين ينظرون إلى الأمور على حقيقتها. أولئك حتماً يصلون إلى الحقيقة كما هي.",
  "13": "مثلما يتخلل المطر البيت ذا السقف الرديء، كذلك الرغبة الشديدة (rāga) التي تتخلل الذهن الذي لم يتم تهذيبه بتأمل تنمية الهدوء (شماتا Samatha)، والبصيرة (فيباسانا Vipassanā).",
  "14": "مثلما أن المطر لا يمكنه أن يتخلل البيت المسقوف بعناية، كذلك الرغبة الشديدة لا يمكنها أن تتخلل الذهن الذي تم تهذيبه بعناية، بتأمل تنمية الهدوء والبصيرة.",
  "15": "في حياته كما بعد مماته، يتغم فاعل الأمور الهدامة في كلا الوجودين، فيشعر بالهم ويعاني من الكرب عندما يرى فساد أعماله.",
  "16": "في حياته كما بعد مماته، يبتهج ذاك الذي يقوم بأفعال الفضيلة، فيبتهج في كلا الوجودين. يبتهج ويبتهج كثيراً عندما يرى نقاء أفعاله.",
  "17": "في حياته كما بعد مماته، يتحسر فاعل الأمور الهدامة ويندب: لقد قمت بالأمور الهدامة. ويصيبه عذاب أكبر عندما يُعاد ميلاده في أحد عوالم المعاناة.",
  "18": "في حياته كما بعد مماته، يسعد من يقوم بالفضائل في كلا الوجودين، فيقول بابتهاج: لقد قمت بكل هذه الفضائل. وسوف يبتهج أكثر عندما يُعاد ميلاده في عالم الوجود البهيج (suggati).",
  "19": "الشخص الذي يقرأ النصوص النقية Tipitaka، أي تعاليم بوذا، ويُهملها، حاله كحال ذلك الراعي الذي يعد الماشية التي يملكها غيره. فمثل هذا الشخص لا نصيب له من حياة التقشف والزهد.",
  "20": "قد يقرأ شخص ما القليل من النصوص النقية (تعاليم بوذا)، لكنه يتدرب بناءً على الدارما، فيقطع الرغبة الشديدة من جذورها، ويقطع الكره والوهم. ويتمتع بالفهم السليم للدارما، وذهنه متحرر من السموم الذهنية، فلا يتعلق بهذا العالم أو بما وراءه. لمثل هذا الشخص نصيب من الحياة الروحانية.",
  "chap2": "الحضور الذهني",
  "21": "الحضور الذهني هو الطريق إلى اللاموت، وغيابه هو الطريق إلى الموت. فمن تمتع بهذا الحضور لا يموت، أما من افتقدوه فهم أشبه بالأموات.",
  "22": "حين يعي الحكيم ذلك كله، فإنه يبتهج لكونه حاضراً، يبتهج لكونه في عالم النبلاء (ariyas).",
  "23": "لا يثني الحكيم عن ممارسة تأمل تنمية الهدوء وتأمل تنمية البصيرة. فهو حاضر دائماً، يجتهد بثبات لإدراك النيرفانا.. نيرفانا لا مثيل لها، متحررة من القيود الأربعة.",
  "24": "إذا كان الفرد منتبهاً، حاضر الذهن، نقياً في فكره وكلامه وأفعاله.. وإذا كان يقوم بكل شيء بعناية واهتمام، مقيداً حواسه، كاسباً عيشه بحسب الدارما وهو يقظ. فإنه حينئذ سيذيع صيته.",
  "25": "يجعل ذو الحكمة من نفسه جزيرة مستعصية على الفيضان. وذلك، من خلال المثابرة، والحضور الذهني، والانضباط، والسيطرة على الحواس.",
  "26": "يسلم الأحمق والجاهل نفسيهما للإهمال، أما ذو الحكمة فيصون حضوره الذهني كجوهرة قيمة.",
  "27": "لذلك، على الإنسان ألا يكون مهملاً أو مدمناً على المتع الحسية. فالشخص المتمكن من الحضور الذهني، من خلال ممارسة تأمل تنمية الهدوء وتأمل تنمية البصيرة، يعيش تجربة السعادة القصوى – أي النيرفانا.",
  "28": "عندما يبدد ذو الحكمة الغفلة من خلال الحضور الذهني- وهو من صعد برج الحكمة، وتحرر من الأسى – فإنه ينظر بحزن إلى الكائنات التي تتألم. فمثلما ينظر الواحد من أعلى قمة الجبل نحو أولئك الذين في السهل تحته، كذلك ينظر ذو الحكمة للأمور الدنيوية التي تمثل الحمق والجهل.",
  "29": "ذو الحكمة حاضر ذهنه بين الغافلين، ومنتبه جداً بين أولئك الذين يعيشون في غفوة. وهو بذلك مثل حصان السباق الذي يستمر في عدوه تاركاً خلفه الخيول المتعبة.",
  "30": "من خلال الحضور الذهني، أصبح Magha ملكاً على كائنات الديفا. فالثناء دائماً للحضور، والذم للغفلة.",
  "31": "إن الراهب الذي يجد البهجة في الحضور الذهني، ويرى الخطر في الغفلة، يسير في طريقه كالنار تحرق كل القيود والأغلال، صغيرها وكبيرها.",
  "32": "إن الراهب الذي يجد البهجة في الحضور الذهني، ويرى الخطر في الغفلة لا يمكنه أن يتراجع، فهو بالفعل قريب إلى النيرفانا.",
  "chap3": "الذهن",
  "33": "الذهن قابل للإثارة وغير ثابت، ومن الصعب السيطرة عليه وضبطه وصونه. وذو الحكمة يدرب ذهنه؛ على غرار صناع السهام، إذ يسوون الأسهم.",
  "34": "كما ترتعش السمكة عندما نخرجها من الماء وتلقى على أرض جافة، كذلك يرتعش الذهن حين يخرج من العالم الحسي ويفر إلى عالم المارا.",
  "35": "من الصعب السيطرة على الذهن، فهو ينطلق ويهبط بسرعة وخفة حيث يجد السرور. فمن المفيد إذن أن تروض الذهن، فالذهن المروض بشكل جيد يجلب السعادة.",
  "36": "من الصعب رؤية الذهن، فهو لطيف في دقته، ينطلق ويهبط حيث يجد السرور. فينبغي على ذي الحكمة إذن أن يصون ذهنه، فالذهن المصون يجلب السعادة.",
  "37": "يجول الذهن بعيداً ويتحرك هنا وهناك وحيداً. فهو غير مادي، يقطن في كهف القلب. أما أولئك الذين يسيطرون على ذهنهم، فيتحررون من قيود المارا.",
  "38": "إذا كان ذهن الشخص غير ثابت، وإذا كان جاهلاً بالدارما الحقيقية، وإذا كان اعتقاده متزعزعاً ومضطرباً، وكذا ثقته وتوقه، فحكمته لن تكتمل أبداً.",
  "39": "إذا كان ذهن الشخص خالياً من الرغبة الشديدة، ولم يكن مبتلى بالكره والغضب، وكان منتبهاً، فلا خطر أمامه.",
  "40": "لأننا نعلم أن هذا الجسم مثل جرة من الصلصال (أي هش)، وحتى نجعل الذهن آمناً (من السموم الذهنية) مثل بلدة حصينة، ينبغي على الواحد منا أن يحارب المارا بسلاح الحكمة. كما ينبغي أن يستمر في صون ذهنه، وألا يشعر بتعلق وتشبث بما ناله.",
  "41": "قريباً سيلقى الجسد خالياً من الوعي في التراب، منبوذاً مثل قطعة خشب لا قيمة لها.",
  "42": "قد يؤذي اللص لصاً ما، وقد يؤذي عدو عدواً ما، لكن الذهن الموجه خطأً تجاه نفسه يتسبب بخطر أعظم بكثير.",
  "43": "لا يمكن لأم أو أب أو أي قريب آخر أن ينفع شخصاً أكثر من ذهنه الموجه بشكل سليم.",
  "chap4": "الزُّهور",
  "44": "من سيختبر ويُدرك هذه الأرض (أي الجسد)، وعالم الياما (وهو عالم المعاناة الشديدة [نيرایا])، وعالم الحيوان، وعالم الكائنات الواقعة في الفاقة العظيمة، تلك التي تُشكّل عوالم الكائنات التعيسة)، وعالم البشر، وعالم الديفا؟ مَن سيُدرك ويفهم طريق الدارما، الذي شُرح خير شرح، وكأنه الخبير في الأزهار يقطف ويختار؟",
  "45": "الإنسان النبيل هو الذي سيدرك هذه الأرض وعالم البشر وعالم الديفا. هذا النبيل هو الذي سيُدرك ويفهم طريق الدارما، التي شُرحت خير شرح. مثله مثل الخبير في الأزهار يقطف ويختار.",
  "46": "إن الذي يدرك أنّ هذا الجسد زائل كزَبَد الماء، ويُدرك أنّه غير جوهري كالسراب، سيقطع أسهم أزهار المارا، ولا يراه الموت.",
  "47": "مَن ينغمس [من غير أن يشعر بالاكتفاء] في قطف الأزهار واختيارها، ومَن تعلّق ذهنه بالمتع الحسيّة، يجرفه الموت كما يكتسح الفيضان قرية ذاهلة نائمة.",
  "48": "المنغمس في قطف الأزهار واختيارها، والمتعلّق ذهنه بالمتع الحسّية، يقهره الموت.",
  "49": "كما النحلة التي تجمع الرحيق وتحوم من دون أن تُفسد الزهرة أو لونها أو عبيرها، دَع الراهب [أو الحكيم] يسكن ويتعامل في القرية من دون أن يؤثر في اعتقاد أهلها وتوقهم، أو في كرمهم وثروائهم.",
  "50": "ينبغي ألا ينظر المرء إلى أخطاء الآخرين أو إلى ما يفعلون وما لا يفعلون من أمور بنّاءة أو هدّامة. إنما عليه أن ينظر وحسب إلى ما قام به وما لم يقم به من الأمور البنّاءة أو الهدّامة.",
  "51": "تماماً، كالزهرة زاهية الألوان التي تفتقد العبير فلا تمنح حاملها عطرها، هي كلمات بوذا المنمقة التي تتحلى بالبلاغة في نظمها. فهي لا تُفيد مَن لا يتدرب على الدارما.",
  "52": "كما أنّ الزهرة الجميلة ذات الرائحة الزكيّة تمنح حاملها عطرها، كذلك كلمات بوذا التي تتحلى بالبلاغة في نظمها، تُفيد مَن يتدرب على الدارما.",
  "53": "على الإنسان أن يفعل الكثير من الأعمال البنّاءة، مثلما نحصل على أكاليل الزهور من أكوام الأزهار.",
  "54": "لا يُمكن لعبير الزهور أن ينتشر عكس اتجاه الريح، وكذا رائحة الصندل، أو الياسمين العربي. أما عطر الأخيار فينتشر في كل الاتجاهات، وكذلك عطر ذوي الفضيلة.",
  "55": "هناك عطور الصندل واللوتس والياسمين، لكنّ عطر أصحاب الفضيلة يفوق كل العطور.",
  "56": "رائحة خشب الصندل خفيفة، لكنّ عطر أصحاب الفضيلة هو الأقوى، فتنتشر رائحته حتى في عوالم الديفا.",
  "57": "لا يُمكن لكائنات المارا أن تجد الطريق الذي اتخذه مَن تحلّوا بالفضيلة [السلوك السليم]، والذين يعيشون بحضور ذهني، والذين تحرروا من السموم الذهنية من خلال الإدراك الكامل.",
  "58": "كما أنّ زهرة اللوتس جميلة عَطِرة الرائحة، ولكنّها قد تنمو فوق كومة قُمامة على قارعة الطريق،",
  "59": "كذلك قد يظهر، ومن كومة قُمامة من الكائنات، تلميذٌ من تلامذة بوذا، يُنير بحكمته إلى المدى البعيد فوق العميان.",
  "chap5": "الأحمق",
  "60": "طويل هو الليل لمن لم يستنر بعدُ، طويلة هي الرحلة للمسافر المتعب، طويلة هي السمسارا Samsāra للأحمق الجاهل بالدارما الحقيقية.",
  "61": "إذا كان المرء يسعى للرفقة ولم يجد رفيقاً خيراً منه أو مثله، فليعزم على أن يمضي وحيداً، فلا رفقة مع الأحمق.",
  "62": "عندي أبنائي، عندي ثروتي. بهذا الشعور بالتعلّق يُبتلى الأحمق. وفي حقيقة الأمر، ليس للأحمق نفسٌ يملكها، فكيف يكون الأبناء والثروة ملكاً له؟",
  "63": "قد يكون الأحمق الذي يعرف أنه أحمق حكيماً لمعرفته بذلك. أما الأحمق الذي يظن أنه حكيم، فهو بالفعل يُدعى أحمق.",
  "64": "الأحمق، وإن ارتبط بشخص حكيم طوال حياته، لن يفهم الدارما تماماً، مثله مثل المغرفة التي لا تعرف طعم الحساء.",
  "65": "الشخص الذكي، وإن رافق شخصاً حكيماً للحظة، يفهم الدارما بسرعة، تماماً مثل اللسان الذي يعرف طعم الحساء.",
  "66": "الحمقى يمضون في هذه الحياة مع أنفسهم وكأنها عدوّ، يفتقرون للذكاء فيقومون بكارما سيئة تجني ثماراً مرّة.",
  "67": "لا يكون الفعل بنّاءً إذا المرء ندم على فعله، وبكى وانتحب نتيجة لذلك الفعل.",
  "68": "يكون الفعل بنّاءً إذا لم يندم المرء على فعله، وإذا كان الشخص سعيداً ومسروراً بثمار هذا الفعل.",
  "69": "يظن الأحمق أنّ الفعل الهدّام أو الشرّ حلو كالعسل ما لم تظهر عواقبه، ولكن حين تظهر هذه العواقب، يعاني الأحمق منها.",
  "70": "يظن الأحمق أنّ قيمة الشخص تكمن في الزهد والتقشف في تناول الطعام وحسب. ولكنّ ذلك لا يعادل، ولو جزءاً يسيراً، قيمة أولئك الأشخاص الذين فهموا تعاليم الدارما بالكامل.",
  "71": "لا تنشأ عواقب الفعل الهدّام والشرير فوراً، تماماً كالحليب الطازج الذي لا يتخثر مباشرة. فهي تتبع الأحمق وتُحرقه كجمر الفحم تحت الرماد.",
  "72": "لا ينال الأحمق من صيته وشهرته سوى الأذى، فهما تفسدان فضائله.",
  "73": "يرغب الراهب الأحمق في تحصيل المديح على خصال ليست عنده، وأن تكون له أولوية بين الرهبان، وسلطة في الأديرة، وتبجيل من أشخاص لا صلة لهم به.",
  "74": "يجب أن يعتقد عامة الناس وجميع الرهبان أنني أنا سبب كل ما يحدث. فليطيعوني إذن في كل الأمور صغيرها وكبيرها. هكذا يفكر الأحمق، فيكبر غروره ويزداد طمعه.",
  "75": "هناك طريق يؤدي إلى المنافع المادية، أما الطريق التي تؤدي إلى النيرفانا فمختلفة. وعندما يفهم تلميذ بوذا هذا تمام الفهم، لا يعود يبتهج للمنافع الدنيوية والتبجيل والشهرة، بل يدرّب نفسه على الخلوة والتجرّد وإدراك النيرفانا.",
  "chap6": "الحكيم",
  "76": "انظر إلى الرجل الحكيم الذي يشير إلى أخطائك وكأنه دليلك إلى كنز دفين. إنّ مصاحبة مثل هذا الحكيم الذي يؤنّب على فعل الخطأ تجلب النفع لا الضرر.",
  "77": "على ذي الحكمة أن يقدّم النصح للحيلولة دون ارتكاب الآخرين الأخطاء. مثل هذا الإنسان يحترمه الأخيار ويكرهه الأشرار.",
  "78": "ينبغي ألّا يربط المرء نفسه برفاق السوء الفاسدين، بل ينبغي أن يرتبط بالأصحاب الأخيار والنبلاء.",
  "79": "من ينهل من الدارما يعش سعيداً بذهن صافٍ، والإنسان الحكيم هو الذي يسعد بالدارما التي يوضّحها النبلاء.",
  "80": "من يصنع قنوات الري يوجه الماء، وصنّاع السهام يسوّون الأسهم، والنجارون يشكلون الخشب، أما الحكماء فيروضون أنفسهم.",
  "81": "كالجبل الصخري لا تهزه الريح، كذلك ذو الحكمة لا يُربكه الملام أو المديح.",
  "82": "كالبحيرة العميقة الصافية الهادئة، يُصبح الحكيم هادئاً بعد استماعه لتعاليم الدارما.",
  "83": "حقاً، يتخلّى من يتحلّى بالفضيلة عن التعلّق بجميع الأشياء، فلا يتحدث برغبة حسّية. وحين يواجه الحكيم بالمتعة أو الأسى، لا يُظهر نشوة أو اكتئاباً.",
  "84": "مَن لا يقوم بالأعمال الهدّامة لأجل نفسه أو الآخرين، ولا يتمنّى البنات والبنين، أو الثراء أو الملك، من خلال الفعل الهدّام، ولا يتمنّى النجاح عبر وسائل ملتوية، مثل هذا المرء يتحلّى بالفضيلة حقاً، وهو حكيم وعادل.",
  "85": "قلّة من الناس من تصل الشاطئ الآخر (أي النيرفانا)، والباقون يمشون جميعاً على ضفة هذا الشاطئ.",
  "86": "أما الذين يتدربون بناءً على الدارما فسيصلون الشاطئ الآخر، بعد اجتياز عالم الموت العسير جداً عبوره.",
  "87": "ذو الحكمة هو من تخلّى عن الحالات السوداوية، فصار لزاماً عليه أن يُنمّي الحالات البنّاءة المشرقة. وهو مَن يترك المساكن المألوفة ليصير بلا مأوى، في خلوة، حيث من الصعب أن يجد الإنسان العادي السرور فيها.",
  "88": "وهناك، عليه أن يسعى إلى السرور بعد أن تخلّى عن المتع الحسّية وعن اشتهاء أي شيء، فيُنقّي نفسه من كل السموم الذهنية في الذهن.",
  "89": "أولئك الذين طوّروا ذهنهم جيداً بعوامل الاستنارة، وتخلّصوا من كل اشتهاء، الذين يبتهجون لتخلّيهم عن التعلّق.. مثل هؤلاء، ومع تخلّصهم من كل السموم والسموم الذهنية Āsava، قد امتلؤوا بنور الحكمة، فصاروا يشعّون نوراً، ونالوا التحرّر في هذا العالم.",
  "chap7": "الأرهات",
  "90": "الشقاء غير موجود بالنسبة إلى الأرهات Arahat الذي أكمل رحلته، والذي تحرّر من الأسى ومن كل شيء، والذي تخلّى عن كل القيود.",
  "91": "أولئك الذين يتمتّعون بالحضور الذهني يجتهدون ويثابرون، ولا يتعلّقون بحياة المنازل. مثلهم مثل البجع الذي يترك البركة الموحلة، هكذا يتركون حياة المنازل.",
  "92": "لا يَخزنُ الأرهات أي شيء، وعندما يحصل على الطعام يتأمّل فيه جيداً. فغايته التحرّر من الوجود وتحقيق النيرفانا. أما نهاية طريقه فلا يُمكن اقتفاؤها، مثلها مثل مسار الطيور في السماء.",
  "93": "يخلو الأرهات من السموم الأخلاقية، فلا يتعلّق بالطعام، وغايته التحرّر من الوجود وتحقيق النيرفانا. أما نهاية طريقه فلا يُمكن اقتفاؤها، مثلها مثل مسار الطيور في السماء.",
  "94": "إنّ الأرهات الذي يتمتّع بملكات حسّية هادئة مثل الخيل التي روّضها الحوذي جيداً، وهو خالٍ من الكبر والسموم الأخلاقية. مثل هذا الأرهات تقدّره كائنات الديفا.",
  "95": "مثل الأرض، يتحلّى الأرهات بالصبر فلا يُستثار غضباً. وهو ثابت لا تشوبه مباهج الحياة أو نوازلها أو تثير اضطرابه. وهو هادئ ونقي مثل البحيرة الصافية غير العكرة. لمثل هذا الأرهات لن يكون هناك تكرار للميلاد.",
  "96": "الأرهات هادئ في ذهنه وهادئ في كلامه، وكذا في أفعاله. وهو يعرف الدارما بالفعل، خالٍ من السموم الذهنية، لا تشوبه مباهج الحياة ونوازلها ولا تُثير اضطرابه.",
  "97": "ذلك الذي حقّق الإدراك الكامل وتحرّر من الإيمان الأعمى والمتذاجة، والذي أدرك النيرفانا، والذي قطع كل ما يربطه بهذا العالم واحتمالات دائرة إعادة الميلاد، والذي أنهى جميع عواقب الأفعال البنّاء منها والهدّام، والذي تخلّص من كل رغباته، هو بالفعل أنبل الناس.",
  "98": "في القرية أو الغابة، في الوادي أو على التلّة، حيثما يعيش الأرهات يحلّ السرور.",
  "99": "الغابات تجلب البهجة، لكنّ المتشبّثين بالعالم لا يجدون فيها بهجة. فقط أولئك الذين تخلّصوا من الرغبة الشديدة والاشتهاء يجدون البهجة فيها، لأنهم لا يسعون إلى المتع الحسّية.",
  "chap8": "الآلاف",
  "100": "كلمة واحدة مفيدة، يسكن المرء لسماعها، خير من ألف كلمة بلا فائدة، وغير مرتبطة بإدراك النيرفانا.",
  "101": "عبارة واحدة مفيدة، يسكن المرء لسماعها، خير من ألف عبارة بلا فائدة، وغير مرتبطة بإدراك النيرفانا.",
  "102": "قراءة عبارة واحدة من تعاليم الدارما، يسكن المرء لسماعها، خير من قراءة مئات العبارات غير المرتبطة بإدراك النيرفانا، ولا فائدة منها.",
  "103": "قد ينتصر المرء على ألف رجل في ألف معركة، غير أن أعظم المنتصرين هو من ينتصر على نفسه.",
  "104": "أن تنتصر على أعدائك الداخليين خير من أن تنتصر على أعدائك الخارجيين.",
  "105": "فمن انتصر داخلياً لن يتمكن من هم خارجه أن ينتصروا عليه، حتى ولو كانوا من كائنات الديفا أو المارا.",
  "106": "قد يقدم المرء العطايا شهرياً، بآلاف القطع النقدية، ولمدة مئة عام. لكن خير له من ذلك كله أن يُبجل لحظة واحدة راهباً أو متدرباً على تنمية البصيرة.",
  "107": "قد يتعهد العديد من الناس النار المقدسة في الغابة، ولكن لو أظهر المرء التبجيل للراهب لحظة واحدة، لكان ذلك حقاً أفضل من مئة عام في تقديم الأضاحي.",
  "108": "حتى ينال الخير والفضيلة، قد يقوم المرء في هذا العالم، طوال السنة، بعطايا كثيرة أو قليلة، كأضاحٍ. لكن هذه العطايا جميعها لا تعادل رُبع الخير الذي يُمكن أن يناله من تبجيل النبلاء، الذين يسيرون على الطريق السليم.",
  "109": "الإنسان الذي يُقدر ويُكرم أولئك الأكبر سناً والأكثر فضيلة، يغنم أربع منافع: طول العمر، والجمال، والسعادة، والقوة.",
  "110": "يوم واحد من حياة ذي الفضيلة، المجتهد في ممارسة تنمية الهدوء وتأمل البصيرة، خير من مئة سنة من حياة الشخص غير السوي، الذي لا يُسيطر على حواسه.",
  "111": "يوم واحد في حياة إنسان حكيم، يجتهد في ممارسة تأمل تنمية الهدوء وتأمل تنمية البصيرة، خير من مئة سنة في حياة إنسان جاهل لا يُسيطر على حواسه.",
  "112": "يوم واحد من حياة الإنسان المجتهد، بكل جِد ونشاط، في ممارسة تنمية الهدوء وتأمل البصيرة، خير من مئة سنة من حياة الشخص البليد الكسول، الذي لا يُسيطر على حواسه.",
  "113": "يوم واحد من حياة الإنسان المدرك لنشوء وزوال المكونات الخمسة، خير من مئة سنة من حياة الشخص الذي لا يُدرك ذلك.",
  "114": "يوم واحد من حياة الإنسان المدرك للنيرفانا خير من مئة سنة من حياة الشخص الذي لا يُدركها.",
  "115": "يوم واحد من حياة الإنسان الذي يفهم الدارما النبيلة خير من مئة سنة من حياة الشخص الذي لا يفهمها.",
  "chap9": "الشر",
  "116": "سارِع للقيام بالأفعال البنّاءة، وامنع ذهنك عن الأفعال الهدّامة. إذا تباطأ المرء في القيام بالأفعال البنّاءة، مال ذهنه نحو الأفعال الهدّامة.",
  "117": "إذا قام المرء بفعل هدّام، فلا ينبغي له أن يكرره، ولا ينبغي له أن يبتهج به. فتراكم الأفعال الهدّامة يؤدّي إلى المعاناة.",
  "118": "إذا قام المرء بفعل بنّاء، فليكرره، وليبتهج به. فتراكم الأفعال البنّاءة يؤدّي إلى السعادة.",
  "119": "حتى مَن يقوم بفعل هدّام، يرى نصيباً من الخير ما لم تنضج ثمار أفعاله الهدّامة. ولكن حين تنضج تلك الثمار، حينئذٍ يرى عواقب أفعاله الهدّامة.",
  "120": "حتى مَن يقوم بفعل بنّاء، يرى نصيباً من المعاناة ما لم تنضج ثمار أفعاله البنّاءة. ولكن حين تنضج تلك الثمار، يرى عواقب أفعاله البنّاءة.",
  "121": "لا تستهن بالفعل الهدّام مهما كان بسيطاً، ولا تقل: لن يأتيني شرّ منه. فمثلما تمتلئ الجرة بقطرات الماء المتساقطة، يمتلئ الأحمق بالأفعال الهدّامة حتى لو جمعها شيئاً فشيئاً.",
  "122": "لا تستهن بالفعل البنّاء مهما كان بسيطاً، ولا تقل: لن يأتيني نفع منه. فمثلما تمتلئ الجرة بقطرات الماء المتساقطة، يمتلئ الحكيم بالأفعال البنّاءة حتى لو جمعها شيئاً فشيئاً.",
  "123": "كما يتجنّب التاجر الذي يحمل الكثير من الثروات وليس معه سوى حراسة بسيطة طريقاً خطراً، وكما يتجنّب المرء السمّ، هكذا ينبغي تجنّب الأفعال الهدّامة.",
  "124": "إذا لم يكن في اليد جرح، يُمكن للمرء أن يحمل السمّ بيده، فالسمّ لا ينفذ من خلال الجلد السليم. وبالمثل، لا يوجد فعل هدّام لمَن لا يقوم به.",
  "125": "مَن يؤذي إنساناً بريئاً لا يضمر سوءاً، ونقياً لا تشوبه شائبة، فإنّ عاقبة فعله الهدّام سترتدّ عليه، تماماً كالغبار الذي يُرمى عكس اتجاه الريح.",
  "126": "بعضهم يُولدون من رحم امرأة، وفاعلو الأفعال الهدّامة يُعاد ميلادهم في عوالم المعاناة، وفاعلو الأفعال البنّاءة يُعاد ميلادهم في عوالم السعادة، أما مَن تحرروا من السموم الذهنية فيبلغون النيرفانا.",
  "127": "ليس في السماء، ولا في وسط المحيط، ولا في شقوق الجبال، ولا في أي مكان في هذا العالم، مَن يُمكنه الهروب من عواقب أفعاله الهدّامة.",
  "128": "ليس في السماء، ولا في وسط المحيط، ولا في شقوق الجبال، ولا في أي مكان في هذا العالم، مَن لا يغلبه الموت.",
  "chap10": "العقاب",
  "129": "جميع الكائنات تخاف من العقاب، وجميع الكائنات تخاف من الموت. لذا، فليضع المرء نفسه مكان الآخرين، ولا يقتل أو يتسبب في قتل أحد.",
  "130": "جميع الكائنات تخاف من العقاب، والحياة عزيزة على الجميع. لذا، فليضع المرء نفسه مكان الآخرين، ولا يقتل أو يتسبب في قتل أحد.",
  "131": "مَن يؤذي الكائنات التي تنشد السعادة بفعله الهدّام، طمعاً في تحقيق سعادته، لن يجد السعادة بعد مماته.",
  "132": "مَن لا يؤذي الكائنات التي تنشد السعادة بفعله الهدّام، طمعاً في تحقيق سعادته، سيجد السعادة بعد مماته.",
  "133": "لا تتحدث بخشونة مع أحد، فمَن تتحدث إليهم قد يردّون عليك بالمثل. حقاً، إنّ الحديث الغاضب مؤلم، وقد يرتدّ إليك العقاب بسببه.",
  "134": "إذا كنت هادئاً كالجرس المحطم، فقد حققت النيرفانا، ولن تجد في نفسك خصومة أو شقاقاً.",
  "135": "مثلما يسوق الراعي الماشية بعصاه نحو المرعى، كذلك يسوق الكِبر والموت حياة الكائنات.",
  "136": "عندما يقوم الأحمق بالفعل الهدّام، فإنه لا يُدرك عواقبه. لكنّ فاعل الأفعال الهدّامة يحترق بعواقب أفعاله، تماماً كمن تحرقه النار.",
  "137": "مَن يعاقب أو يؤذي مَن لا يستحق العقاب ولا يحمل ضغينة، فسوف يواجه بسرعة واحدة من هذه الحالات العشر:",
  "138": "معاناة شديدة، أو فاقة، أو إصابة في الجسد، أو مرض شديد، أو فقدان العقل،",
  "139": "أو غضب الحاكم، أو اتهام خطير، أو فقدان الأقارب، أو دمار الثروة،",
  "140": "أو حريق يلتهم بيته. وبعد مماته، يُعاد ميلاده في عوالم المعاناة الشديدة.",
  "141": "لا المشي عارياً، ولا تلبيد الشعر، ولا الصيام، ولا النوم على الأرض، ولا التلطخ بالتراب، ولا القرفصاء، يُمكنها أن تُنقي المرء الذي لم يتجاوز الشكّ.",
  "142": "حتى لو كان المرء يتزيّن بالثياب، ولكنه هادئ، ومسيطر على حواسه، ومستقر في الفضيلة، ونقي، ولا يؤذي أي كائن، فهو بحقّ براهمن، وهو بحقّ ناسك، وهو بحقّ راهب.",
  "143": "هل هناك في هذا العالم إنسان يمنعه الحياء من ارتكاب الأفعال الهدّامة، فلا يطاله اللوم، تماماً كما يتجنب الحصان الأصيل السوط؟",
  "144": "كالحصان الأصيل الذي يلمسه السوط، كُن مجتهداً ومفعماً بالرهبة (تجاه السمسارا). ومن خلال الإيمان، والفضيلة، والجهد، والتركيز، وفهم الدارما، والتمتع بالمعرفة والسلوك السليم، والحضور الذهني، اترك خلفك هذه المعاناة العظيمة.",
  "145": "من يصنع قنوات الري يوجه الماء، وصنّاع السهام يسوّون الأسهم، والنجارون يشكلون الخشب، أما الحكماء فيروضون أنفسهم.",
  "chap11": "الشيخوخة",
  "146": "لماذا الضحك؟ ولماذا الابتهاج، بينما هذا العالم يحترق دائماً؟ وأنتم الذين يلفكم الظلام، ألا تبحثون عن النور؟",
  "147": "انظر إلى هذا الجسد المزيّن، فهو كومة من القروح، ومجموعة من الأجزاء، ومحل للأمراض، وفيه الكثير من التصورات والأفكار، فليس له ثبات أو دوام.",
  "148": "هذا الجسد يبلى بمرور الزمن، وهو وكر للأمراض، وسريع العطب. فهذا الهيكل العفن يتداعى، ونهاية الحياة هي الموت.",
  "149": "هذه العظام الرمادية، التي تشبه القرع المطروح في الخريف، أيّ بهجة في النظر إليها؟",
  "150": "هذا الجسد مبني من عظام، مكسو بلحم ودم، وفيه يكمن الهرم، والموت، والكبر، والرياء.",
  "151": "حتى عربات الملوك المزينة تبلى، وكذلك هذا الجسد يدركه الهرم. أما الدارما التي يتحلى بها الأخيار فلا تهرم أبداً، فهكذا يخبر الأخيار بعضهم بعضاً.",
  "152": "الإنسان قليل العلم يهرم مثل الثور؛ يزداد لحمه، ولكن لا تزداد حكمته.",
  "153": "عبر رحلة طويلة من إعادات الميلاد، بحثتُ عن بنّاء هذا البيت، فلم أجده. وتكرار الميلاد معاناة.",
  "154": "يا بنّاء البيت، لقد رأيتك الآن، ولن تبني هذا البيت ثانية؛ فقد تحطمت كل أضلاعك، وانكسرت دعامة بيتك. والآن، حقق ذهني النيرفانا، ووصلتُ إلى نهاية الرغبة الشديدة.",
  "155": "أولئك الذين لم يعيشوا حياة الزهد في شبابهم، ولم يجمعوا الثروات، هم مثل طيور البلشون الهرمة التي تقف حزينة في بركة تخلو من الأسماك.",
  "156": "أولئك الذين لم يعيشوا حياة الزهد في شبابهم، ولم يجمعوا الثروات، يستلقون الآن كالأقواس المحطمة، يتحسرون على ما فاتهم.",
  "chap12": "النفس",
  "157": "إذا أدرك المرء أهمية نفسه، فعليه أن يصونها ويحميها بعناية. وعلى ذي الحكمة أن يظل متيقظاً في واحدة من فترات العمر الثلاث (الشباب، أو الكهولة، أو الشيخوخة).",
  "158": "على المرء أولاً أن يوجه نفسه نحو السلوك القويم، ومن ثم ينصح الآخرين. فبذلك لا يطاله اللوم.",
  "159": "إذا قام المرء بتدريب نفسه كما ينصح الآخرين، وحقق السيطرة الكاملة عليها، فإنه حينئذٍ يستطيع تدريب الآخرين. فحقيقة الأمر أن السيطرة على النفس هي الأصعب.",
  "160": "المرء سيد نفسه، فمن غيره يكون سيداً له؟ فمن خلال السيطرة التامة على النفس، يحقق المرء السيادة التي يصعب تحقيقها.",
  "161": "الفعل الهدّام الذي يقوم به الأحمق، والنابع منه، والمتسبب فيه، يسحقه تماماً كما يحطم الألماسُ الحجرَ الصلد.",
  "162": "الشخص الذي يتسم بسلوك سيئ للغاية، كاللبلاب الذي يلتف حول شجرة فيخنقها، فإنه يفعل بنفسه تماماً ما يتمناه له عدوه.",
  "163": "من السهل القيام بالأفعال الهدّامة الضارة بالنفس، أما القيام بالأفعال البنّاءة والنافعة فهو الصعب جداً.",
  "164": "الأحمق الذي يزدري تعاليم الأرهات والنبلاء الذين يعيشون وفقاً للدارما، بسبب وجهات نظره الخاطئة، فإنه يجني ثماراً مرّة تدمره، تماماً كفاكهة القصب التي تنمو لتقتل النبتة نفسها.",
  "165": "المرء يقوم بالفعل الهدّام بنفسه، وبنفسه يتلوث. وبالفعل البنّاء يترك المرء الفعل الهدّام، وبنفسه يتطهر. فالنقاء وعدم النقاء يعتمدان على الشخص نفسه، ولا يمكن لأحد أن يطهر أحداً آخر.",
  "166": "لا ينبغي للمرء أن يهمل مصلحته الروحية لأجل مصلحة الآخرين، مهما كانت عظيمة. وحين يدرك المرء مصلحته الروحية، عليه أن يسعى جاهداً لتحقيق الغاية القصوى.",
  "chap13": "العالم",
  "167": "لا تتبع أساليب الحياة الوضيعة، ولا تعش في غفلة، ولا تتبع وجهات النظر الخاطئة، ولا تكن ممن يطيل أمد بقائه في هذا العالم (أي السمسارا).",
  "168": "كن منتبهاً ولا تكن غافلاً. اتبع الدارما وعش في استقامة. فمن يتبع الدارما يعش سعيداً في هذا العالم وفي العالم الآخر.",
  "169": "اتبع الدارما وعش في استقامة، ولا تعش في اعوجاج. فمن يتبع الدارما يعش سعيداً في هذا العالم وفي العالم الآخر.",
  "170": "انظر إلى هذا العالم كفقاعة ماء، وانظر إليه كسراب. فمن ينظر إلى العالم بهذه الطريقة لا يراه ملك الموت.",
  "171": "تعالوا وانظروا إلى هذا العالم، فهو مثل عربة الملوك المزينة. فبينما يغرق الحمقى فيه، لا يجد الحكماء أي تعلق به.",
  "172": "الشخص الذي كان غافلاً في السابق، ثم صار الآن منتبهاً وحاضر الذهن، فإنه ينير هذا العالم كما ينير القمر ليلة البدر حين يخرج من خلف السحاب.",
  "173": "الشخص الذي يمحو أفعاله الهدّامة من خلال القيام بالأفعال البنّاءة، فإنه ينير هذا العالم كما ينير القمر ليلة البدر حين يخرج من خلف السحاب.",
  "174": "هذا العالم يلفه الظلام، وقليلون هم الذين يبصرون فيه. وقليلون هم الذين يذهبون إلى عالم السعادة، مثل الطيور التي تنجو من شباك الصياد.",
  "175": "تطير طيور البجع في مسار الشمس، ويطير الحكماء في الهواء بقدراتهم الروحية. والحكماء الذين هزموا المارا وجنوده، يرحلون من هذا العالم (إلى النيرفانا).",
  "176": "الشخص الذي ينتهك قانون الدارما، ويتحدث بالكذب، ويزدري العالم الآخر، لا يوجد فعل هدّام يعجز عن القيام به.",
  "177": "حقاً، البخلاء لا يذهبون إلى عوالم السعادة، والحمقى لا يمدحون العطاء. أما الحكيم فيبتهج بالعطاء، ولذلك يسعد في العالم الآخر.",
  "178": "إنّ ثمرة بلوغ مرتبة الداخل في التيار (Sotāpatti)، وهي أولى مراحل الاستنارة، أفضل من السيادة على الأرض، وأفضل من الذهاب إلى عوالم السعادة، وأفضل من السيادة على العوالم كلها.",
  "chap14": "بوذا",
  "179": "من لا يمكن هزيمة انتصاره (على الرغبة الشديدة)، والذي لم يتبعه أحد من هذا العالم؛ أي طريق ستسلك لتقتفي أثر بوذا ذا العلم اللامتناهي، والذي لا يترك خلفه أثراً؟",
  "180": "من لا توجد لديه رغبة شديدة تضلله وتجره إلى الوجود ثانية؛ أي طريق ستسلك لتقتفي أثر بوذا ذا العلم اللامتناهي، والذي لا يترك خلفه أثراً؟",
  "181": "حتى كائنات الديفا تغبط الحكماء الذين كرسوا أنفسهم لممارسة تأمل تنمية الهدوء وتأمل تنمية البصيرة، والذين يبتهجون بالخلوة من الرغبات، والذين حققوا الاستنارة والحضور الذهني.",
  "182": "من الصعب أن يولد المرء إنساناً، ومن الصعب أن يعيش حياة فانية، ومن الصعب أن يستمع للدارما الحقيقية، ومن الصعب جداً ظهور البوذا.",
  "183": "عدم القيام بجميع الأفعال الهدامة، والقيام بجميع الأفعال البناءة، وتطهير الذهن (من السموم الذهنية)؛ هذه هي تعاليم البوذات.",
  "184": "الصبر هو أعلى درجات الزهد والتقشف، والنيرفانا هي الغاية القصوى؛ هكذا يقول البوذات. فالذي يؤذي الآخرين ليس بناسك، والذي يضطهد الآخرين ليس براهب.",
  "185": "عدم الشتم، وعدم الإيذاء، والالتزام بالقواعد الأساسية للرهبان، والاعتدال في الأكل، والسكن في مكان منعزل، والمواظبة على ممارسة التأمل؛ هذه هي تعاليم البوذات.",
  "186": "لا يمكن إشباع الرغبات حتى لو أمطرت السماء قطعاً نقدية ذهبية. فالمتع الحسية لا تعطي إلا القليل من السرور والكثير من المعاناة؛ والحكيم يدرك ذلك.",
  "187": "حتى في المتع الإلهية (في عوالم السعادة)، لا يجد تلميذ بوذا الكامل الاستنارة أي بهجة. فهو لا يجد بهجته إلا في إنهاء الرغبة الشديدة.",
  "188": "يلجأ الناس الذين أصابهم الخوف إلى الجبال، والغابات، والحدائق، والأشجار، والأضرحة كملجأ لهم.",
  "189": "لكن هذا ليس بالملجأ الآمن، وليس بالملجأ الأسمى. فمن يلجأ لهذه الأماكن لا يتحرر من جميع أشكال المعاناة.",
  "190": "أما من يلجأ لبوذا، وللدارما، وللسانغا (أي جماعة الرهبان)، فإنه يدرك بحكمته الحقائق الأربع النبيلة.",
  "191": "المعاناة، وسبب المعاناة، والتحرر من المعاناة، والطريق الثماني النبيل الذي يقود إلى التحرر من المعاناة.",
  "192": "هذا هو الملجأ الآمن، وهذا هو الملجأ الأسمى. فمن يلجأ إلى هذا الملجأ يتحرر من جميع أشكال المعاناة.",
  "193": "قد تظن أن الولاء هو مجرد تقديم الزهور، لكن لا شيء يفوق البهجة التي يحصل عليها بوذا من خلال ممارسة الدارما بناءً على الدارما.",
  "194": "مبارك هو ظهور البوذات، ومبارك هو سماع الدارما الحقيقية، ومباركة هي الوحدة بين الرهبان، ومباركة هي حياة الرهبان في وئام.",
  "195": "من يبدي التبجيل لمن يستحقون التبجيل، كالبوذات أو تلامذتهم الذين تخلصوا من السموم الذهنية، والذين تجاوزوا العقبات الروحية، وتخلصوا من الأسى والانتحاب.",
  "196": "من يبدي التبجيل لمثل هؤلاء الذين حققوا السلام والتحرر من الخوف، فإن ميزة تبجيله لا يمكن حصرها.",
  "chap15": "السعادة",
  "197": "حقاً، نحن نعيش بسعادة عندما لا نضمر الكره تجاه من يكرهوننا. فبين أولئك الذين يضمرون الكره، نحن نعيش بلا كره.",
  "198": "حقاً، نحن نعيش بسعادة وبصحة نفسية جيدة بين أولئك المعتلين نفسياً. فبين أولئك المعتلين نفسياً، نحن نعيش بصحة نفسية جيدة.",
  "199": "حقاً، نحن نعيش بسعادة عندما نكون غير متطلعين لامتلاك المتع الحسية بين المتطلعين لامتلاكها. فبين أولئك المتطلعين لامتلاكها، نحن نعيش غير متطلعين إليها.",
  "200": "حقاً، نحن نعيش بسعادة بالغة عندما لا يكون لدينا ما يربطنا بهذا العالم. فنحن نقتات على البهجة مثل كائنات الأبهاسارا.",
  "201": "الانتصار يولد الكره، فالمهزوم يعيش في معاناة. أما من حقق السلام، فإنه يعيش بسعادة بعد أن تخلص من مشاعر الانتصار والهزيمة.",
  "202": "لا توجد نار مثل نار الشهوة، ولا يوجد شر مثل الكره، ولا توجد معاناة مثل المكونات الخمسة (للجسد والذهن)، ولا توجد سعادة تفوق النيرفانا.",
  "203": "الجوع هو أشد الأمراض، والمكونات الخمسة هي أعظم المعاناة. ومن يدرك هذه الحقيقة كما هي، يدرك أن النيرفانا هي السعادة القصوى.",
  "204": "الصحة هي أعظم مكسب، والقناعة هي أعظم ثروة، والثقة هي أعظم قريب، والنيرفانا هي السعادة القصوى.",
  "205": "من تذوق طعم الخلوة والسكينة، وتذوق طعم الدارما، فإنه يتحرر من الخوف والسموم الذهنية.",
  "206": "رؤية النبلاء تجلب السعادة، والعيش معهم سعادة دائمة. والإنسان يسعد دائماً عندما لا يرى الحمقى.",
  "207": "من يمشي في صحبة الحمقى يندم طويلاً، فصحبة الحمقى مؤلمة كصحبة العدو. أما صحبة الحكيم فمبهجة كلقاء الأقارب.",
  "208": "لذا، اتبع الحكيم، والذكي، والعالم، والصبور، والملتزم بمهامه الروحية، والنبيل. اتبع مثل هذا الإنسان الحكيم كما يتبع القمر مسار النجوم.",
  "chap16": "المودة",
  "209": "الشخص الذي ينشغل بما لا ينفعه، ويهمل ما فيه صلاحه، والذي يتخلى عن غايته الروحية وينغمس في المتع الحسية، فإنه سيغبط حتماً أولئك الذين اجتهدوا في ممارسة التأمل.",
  "210": "لا تربط نفسك بمن تحبهم حباً جماً، ولا بمن تبغضهم. فعدم رؤية من تحبهم معاناة، ورؤية من تبغضهم معاناة أيضاً.",
  "211": "لذا، لا تجعل قلبك يتعلق بشيء أو بشخص؛ ففراق من تعلقت بهم مؤلم. أما أولئك الذين ليس لديهم ما يحبونه أو يكرهونه، فلا توجد لديهم قيود.",
  "212": "من المودة ينشأ الأسى، ومن المودة ينشأ الخوف. أما من تحرر من المودة فلا يوجد لديه أسى، فمن أين يأتي الخوف؟",
  "213": "من الحب ينشأ الأسى، ومن الحب ينشأ الخوف. أما من تحرر من الحب فلا يوجد لديه أسى، فمن أين يأتي الخوف؟",
  "214": "من المتع الحسية ينشأ الأسى، ومن المتع الحسية ينشأ الخوف. أما من تحرر من المتع الحسية فلا يوجد لديه أسى، فمن أين يأتي الخوف؟",
  "215": "من الشهوة ينشأ الأسى، ومن الشهوة ينشأ الخوف. أما من تحرر من الشهوة فلا يوجد لديه أسى، فمن أين يأتي الخوف؟",
  "216": "من الرغبة الشديدة ينشأ الأسى، ومن الرغبة الشديدة ينشأ الخوف. أما من تحرر من الرغبة الشديدة فلا يوجد لديه أسى، فمن أين يأتي الخوف؟",
  "217": "من يتحلى بالفضيلة والبصيرة، ويهتدي بالدارما، ويدرك الحقيقة، ويقوم بواجباته الروحية؛ فإنه يكون محبوباً من الجميع.",
  "218": "من يطمح للوصول إلى النيرفانا، ومن لديه ذهن متقد، ومن لا يرتبط ذهنه بالمتع الحسية؛ فإنه يُدعى الذاهب عكس التيار (uddhamsoto).",
  "219": "عندما يعود المسافر بأمان من مكان بعيد بعد غياب طويل، فإن أقاربه وأصدقاءه يستقبلونه بفرح وسرور.",
  "220": "وبالمثل، عندما يرحل من قام بالأعمال البناءة من هذا العالم إلى العالم الآخر، فإن أعماله البناءة تستقبله كما يستقبل الأقارب حبيبهم العائد.",
  "chap17": "الغضب",
  "221": "تخلَّ عن الغضب، وانبذ الكبر، وتجاوز كل القيود. فالأسى لا يطال من لا يتعلق بالجسد والذهن (الناماروبا)، ومن لا يملك شيئاً.",
  "222": "من يكبح غضبه المتصاعد كما يكبح الحوذي العربة المسرعة، هو من أدعوه حوذياً حقاً، أما الآخرون فهم مجرد ممسكين بالأعنة.",
  "223": "اهزم الغضب باللاغضب (بالطيبة)، واهزم الشر بالخير، واهزم البخل بالعطاء، واهزم الكذب بالحقيقة.",
  "224": "على المرء أن يقول الحقيقة، وألا يغضب، وأن يعطي ولو القليل لمن يسأله. فمن خلال هذه الخصال الثلاث، يذهب المرء إلى عالم الديفا.",
  "225": "الحكماء الذين لا يؤذون أحداً، والذين يسيطرون دائماً على أفعالهم، يذهبون إلى الحالة الأبدية (النيرفانا)، حيث لا وجود للأسى.",
  "226": "أولئك الذين يتمتعون باليقظة الدائمة، والذين يتدربون ليلاً ونهاراً، والذين يوجهون أنفسهم نحو النيرفانا، تتلاشى سمومهم الذهنية (الآسافا).",
  "227": "يا أتولا، هذا أمر قديم وليس بجديد؛ فهم يلومون الصامت، ويلومون كثير الكلام، ويلومون المعتدل في كلامه. فلا يوجد أحد في هذا العالم لا يطاله اللوم.",
  "228": "لم يكن، ولن يكون، ولا يوجد الآن شخص يطاله اللوم وحده، أو المديح وحده.",
  "229": "لكن من يمدحه الحكماء بعد مراقبته يوماً بعد يوم، لكونه يتسم بسلوك لا تشوبه شائبة، وبأنه حكيم ومتمتع بالمعرفة والفضيلة؛ فمن ذا الذي يجرؤ على لوم مثل هذا الشخص؟",
  "230": "إنه نقي كعملة من الذهب الخالص، حتى كائنات الديفا تمدحه، بل ويمدحه براهما أيضاً.",
  "231": "احذر من ثورات الجسد، وكن مسيطراً على أفعالك. تخلَّ عن سوء سلوك الجسد، ومارس السلوك السليم بجسدك.",
  "232": "احذر من ثورات اللسان، وكن مسيطراً على كلامك. تخلَّ عن سوء سلوك اللسان، ومارس السلوك السليم بلسانك.",
  "233": "احذر من ثورات الذهن، وكن مسيطراً على أفكارك. تخلَّ عن سوء سلوك الذهن، ومارس السلوك السليم بذهنك.",
  "234": "الحكماء هم الذين يسيطرون على أفعالهم، وأقوالهم، وأفكارهم. فهم حقاً من حقق السيطرة الكاملة.",
  "chap18": "الشوائب",
  "235": "أنت الآن مثل ورقة صفراء، ورسل الموت (الياما) بانتظارك. أنت تقف على مشارف الرحيل، وليس لديك زاد لرحلتك.",
  "236": "فلتجعل من نفسك جزيرة، ولتجتهد، ولتكن حكيماً. ومن خلال التخلص من السموم الذهنية، وتجاوز الدنس، سوف تصل إلى عالم النبلاء الإلهي.",
  "237": "لقد شارف عمرك على الانتهاء، وأنت الآن في طريقك لمقابلة ملك الموت (الياما). ولا توجد محطة ترتاح فيها في طريقك، وليس لديك زاد لرحلتك.",
  "238": "فلتجعل من نفسك جزيرة، ولتجتهد، ولتكن حكيماً. ومن خلال التخلص من السموم الذهنية، وتجاوز الدنس، فلن تعود ثانية إلى الميلاد والهرم.",
  "239": "على ذي الحكمة أن يزيل شوائبه شيئاً فشيئاً، لحظة بلحظة، تماماً كما يزيل الصائغ الشوائب من الفضة.",
  "240": "مثلما يظهر الصدأ على الحديد، ثم يأكل الحديد نفسه، كذلك الأفعال الهدامة التي يقوم بها من يتجاوز الحدود، تقوده إلى عوالم المعاناة.",
  "241": "عدم التكرار هو شوائب التعاليم، وعدم الصيانة هو شوائب البيوت، والكسل هو شوائب الجمال، والغفلة هي شوائب الحارس.",
  "242": "سوء السلوك هو شوائب المرأة، والبخل هو شوائب المعطي. حقاً، الأفعال الهدامة هي شوائب هذا العالم والعالم الآخر.",
  "243": "وأسوأ هذه الشوائب قاطبة هي الجهل، فهو الشائبة الكبرى. فتخلصوا من هذه الشائبة يا رهبان، لتكونوا بلا شوائب.",
  "244": "من السهل على المرء أن يعيش بلا حياء، مثل الغراب، متسم بالوقاحة، والمكر، والعدوانية، والفساد.",
  "245": "ومن الصعب على المرء أن يعيش بحياء، باحثاً دائماً عن النقاء، وغير ملتصق بالأشياء، ومتواضعاً، وبصيراً، ونقياً في حياته.",
  "246": "من يقتل، ويتحدث بالكذب، ويأخذ ما ليس له، ويذهب لزوجة غيره، وينغمس في شرب المسكرات؛",
  "247": "فإنه يحفر قبره بنفسه في هذا العالم.",
  "248": "فلتدرك إذن، أيها الرجل، أن من الصعب السيطرة على الأفعال الهدامة. فلا تدع الطمع والظلم يجلبان لك معاناة طويلة.",
  "249": "الناس يعطون وفقاً لإيمانهم وما يملكون. فمن يشعر بالضيق من طعام وشراب الآخرين، لن يحقق السكون الذهني (التأملي) لا في النهار ولا في الليل.",
  "250": "أما من قطع دابر هذا الضيق، واستأصله تماماً؛ فإنه يحقق السكون الذهني في النهار وفي الليل.",
  "251": "لا توجد نار مثل نار الشهوة، ولا يوجد قبض مثل قبض الكره، ولا توجد شبكة مثل شبكة الوهم، ولا يوجد نهر مثل نهر الرغبة الشديدة.",
  "252": "من السهل رؤية أخطاء الآخرين، ومن الصعب رؤية أخطاء النفس. فالمرء يذرو أخطاء الآخرين كالهباء، أما أخطاء نفسه فيخفيها كما يخفي المخادع نفسه.",
  "253": "من يبحث دائماً عن أخطاء الآخرين، ويسعى دائماً للومهم، فإن سمومه الذهنية تزداد، وهو بعيد كل البعد عن التخلص منها.",
  "254": "لا يوجد أثر في السماء، ولا يوجد ناسك (أرهات) خارج طريق بوذا. فالناس يبتهجون بالعوائق الروحية، أما البوذات فخالون منها.",
  "255": "لا يوجد أثر في السماء، ولا يوجد ناسك خارج طريق بوذا. ولا يوجد شيء مشروط يبقى للأبد، والبوذات لا يتأثرون بأي اضطراب.",
  "chap19": "الإنسان العادل",
  "256": "لا يُعد المرء عادلاً إذا اتخذ قراره بتسرع وتعسف. أما الحكيم فهو من يدرس الأمر جيداً، ويميز بين الخطأ والصواب.",
  "257": "من يحكم بين الآخرين من غير تعسف، ووفقاً للدارما وبإنصاف، ويحمي القانون، فهو من يُدعى عادلاً بحق.",
  "258": "لا يُعد المرء حكيماً لمجرد كونه كثير الكلام. أما من يتسم بالسكينة، والتحرر من الكره والخوف، فهو من يُدعى حكيماً.",
  "259": "لا يُعد المرء متمسكاً بالدارما لمجرد كونه كثير الكلام عنها. أما من سمع القليل من الدارما وأدرك حقيقتها بحدسه، ولم يغفل عنها أبداً، فهو المتمسك بالدارما بحق.",
  "260": "لا يُعد المرء شيخاً (Thera) لمجرد أن رأسه قد اشتعل شيباً؛ فإذا كان يفتقر إلى الفضيلة، فهو شيخ بالاسم فقط.",
  "261": "أما من يتحلى بالحقيقة، والفضيلة، وعدم الإيذاء، والانضباط، والسيطرة على الحواس، ومن تخلص من السموم الذهنية، فهو من يُدعى شيخاً بحق.",
  "262": "لا يصبح المرء إنساناً صالحاً بمجرد بلاغة كلامه أو جمال وجهه، إذا كان يتسم بالحسد، والبخل، والمكر.",
  "263": "أما من استأصل هذه الصفات تماماً، وتخلص من الكره، وهو حكيم، فهو من يُدعى إنساناً صالحاً بحق.",
  "264": "لا يصبح المرء ناسكاً (Samaņa) بمجرد حلاقة رأسه، إذا كان كاذباً وغير منضبط. فكيف يكون ناسكاً وهو ممتلئ بالرغبة والطمع؟",
  "265": "أما من كبح جماح أفعاله الهدامة، صغيرها وكبيرها، فهو من يُدعى ناسكاً، لأنه كبح جماح كل ما هو هدام.",
  "266": "لا يُعد المرء راهباً (Bhikkhu) لمجرد أنه يطلب الصدقة من الآخرين. فمن يتبع أساليب حياة العامة لا يعد راهباً.",
  "267": "أما من تعالى على الأفعال البناءة والهدامة، وعاش حياة روحية، وسار في هذا العالم بوعي وبصيرة، فهو من يُدعى راهباً بحق.",
  "268": "لا يصبح المرء حكيماً (Muni) بالصمت وحده، إذا كان جاهلاً وأحمق. أما الحكيم فهو من يزن الأمور، فيأخذ بما هو بناء ويترك ما هو هدام.",
  "269": "ومن يدرك طبيعة العالمين (الداخلي والخارجي) فهو الحكيم بحق.",
  "270": "لا يُعد المرء نبيلاً (Ariya) إذا كان يؤذي الكائنات الحية. ومن خلال عدم إيذاء جميع الكائنات الحية، يُدعى المرء نبيلاً.",
  "271": "ليس بمجرد الالتزام بالقواعد الأخلاقية، ولا بكثرة العلم، ولا بالدخول في حالات التأمل العميق، ولا بالعيش في خلوة، ولا بالقول: لقد نلت سعادة التحرر التي لا ينالها عامة الناس،",
  "272": "يمكن للراهب أن يطمئن ما لم يحقق التخلص التام من السموم الذهنية (الوصول للأرهات).",
  "chap20": "المسار الروحاني",
  "273": "من بين كلّ المسارات الروحانية، أنبلها مسار النبلاء ذو الفروع الثمانية. ومن بين الحقائق أنبلها الحقائق النبيلة الأربع. ومن بين الحالات أنبلها غياب الرغبة الشديدة. وأنبل الكائنات التي تمشي على رجلين البوذا الذي يرى كلّ شيء.",
  "274": "هذا هو المسار من أجل نقاء الرؤية، ولا مسار غيره. إذا اتبعتموه فسوف تُربكون المارا.",
  "275": "إذا اتبعتم هذا المسار فستضعون نهاية للمعاناة. وقد عرفتم هذا الطريق من خلالي، إنّه الطريق الذي يُحطّم أسهم السّموم الذهنية.",
  "276": "مهمّتكم أن تبذلوا جهدكم، فالبوذات (Tathāgatas) فقط يُرشدون إلى الطريق، وأولئك الذين يتدربون على التأمّل يتحرّرون من قيود المارا.",
  "277": "'كل الأشياء المشروطة متغيّرة'، وعندما ينظر المرء إلى هذا ببصيرة وحكمة، سيستيقظ من المعاناة. هذا هو مسار النقاء.",
  "278": "'كل الأشياء المشروطة معاناة'، وعندما ينظر المرء إلى هذا ببصيرة وحكمة، سيستيقظ من المعاناة. هذا هو مسار النقاء.",
  "279": "'كل الأشياء المشروطة بلا ذات'، وعندما ينظر المرء إلى هذا ببصيرة وحكمة، سيستيقظ من المعاناة. هذا هو مسار النقاء.",
  "280": "الإنسان الذي لا ينهض عندما ينبغي عليه ذلك، والذي رُغم شبابه وقوته، سلّم نفسه للكسل، هذا الكسول ذو الذهن البليد لن ينال مسار الحكمة.",
  "281": "على الإنسان توخي الحذر في كلامه، وأن يكون منضبطاً في ذهنه، وفي جسمه، وألا يرتكب الأمور غير السليمة. على المرء أن يُنقي هذه الثلاثة، ويقوم بالمسار الذي وضحه البوذات.",
  "282": "ألا إنّ الحكمة وليدة التأمل، ومن دون التأمل تضيع الحكمة. إذا عرفنا هذا السبيل بفرغيه: نيل الحكمة وضياعها، وجب على الإنسان الانضباط في سلوكه حتّى تربو الحكمة وتزيد.",
  "283": "يا رهبان! قطعوا أشجار غابة الاشتهاء، لا الأشجار الحقيقية، فغابة الاشتهاء تولّد الخوف. قطعوا أشجار الاشتهاء وكذلك ما ينمو من شجيرات صغيرة تحتها، حتى تتحرّروا من غابة الاشتهاء.",
  "284": "طالما لم يُجتث اشتهاء الرجل للمرأة، مهما كان ضئيلاً، ولم يقطع، سيبقى ذهنه مقيداً مثل العجل الصغير المربوط بأمه.",
  "285": "اقطعوا التعلّق داخلكم كما تُقطف زهرة اللوتس باليد في فصل الخريف. واجتهدوا في مسار السلام (وهو مسار) النيرفانا الذي علمه البوذات.",
  "286": "'هنا سأعيش خلال موسم المطر، وهنا سأعيش في الشتاء والصيف'. هذا ما يُفكّر فيه الأحمق الذي لا يُدرك عائق الموت.",
  "287": "يأخذ الموت من هو شغوف بما لديه من أبناء وغنم، ومن ذهنه متعلّق بهم. شأنه شأن القرية النائمة التي يسحقها فيضان عظيم.",
  "288": "لا يُمكن للأبناء ولا للوالدين أو الأقارب المقرّبين حماية الإنسان. فعند انقضاض الموت عليه، لا الأقارب ولا الأصحاب يُمكنهم حمايته.",
  "289": "وإذ يُدرك هذا الأمر ذو الحكمة، المنضبط الأخلاق والمبادئ، وجب عليه أن يُسارع إلى إزالة العوائق عن المسار المؤدي إلى النيرفانا.",
  "chap21": "منثورات",
  "290": "إذا وجد الإنسان سعادة عظيمة في أن يتخلّى عن مُتَع صغيرة، وَجَبَ على الحكيم أن يتخلّى عن المُتَع الصغيرة لدى رؤيته السعادة العظيمة.",
  "291": "من يسع لنيل سعادته الشخصيّة من خلال التسبب بالألم للآخرين، وهو مكبّل بقيود العدائية، لا يُمكنه التحرّر من هذه العدائية.",
  "292": "أولئك الذين يتركون ما يلزم القيام به، ويقومون بما لا يلزم - المزهرون بأنفسهم وينقصهم الانتباه - تكبر فيهم السّموم الذهنية.",
  "293": "أولئك الذين يدأبون في بذل خير الجُهد في تنمية الحضور الذهني في الجسد، والذين لا يقومون بما لا يلزم القيام به بل يدأبون في القيام بما ينبغي القيام به، والذين يتمتعون بالحضور الذهني السليم والفهم السليم، تنتهي فيهم السّموم الذهنية.",
  "294": "بعد أن يقتل الساعي للتحرّر الأم (رمز الاشتهاء)، والأب (رمز الغرور)، والملكين، ويُدمّر المملكة وجابي مواردها، يتحرّر حينها من المعاناة.",
  "295": "بعد أن يقتل الساعي للتحرّر الأم والأب والملكين، ويُدمّر العائق الخامس وهو النمر (رمز الشك) - يتحرّر الساعي للتحرّر من المعاناة.",
  "296": "تلامذة غوتاما بوذا يستيقظون دائماً من النوم بأذهان واضحة يقظة، وهم ليلاً نهاراً في حضور ذهني دائم تجاه بوذا.",
  "297": "تلامذة غوتاما بوذا يستيقظون دائماً من النوم بأذهان واضحة يقظة، وهم ليلاً نهاراً في حضور ذهني دائم تجاه الدارما.",
  "298": "تلامذة غوتاما بوذا يستيقظون دائماً من النوم بأذهان واضحة يقظة، وهم ليلاً نهاراً في حضور ذهني دائم تجاه السانغا.",
  "299": "تلامذة غوتاما بوذا يستيقظون دائماً من النوم بأذهان واضحة يقظة، وهم ليلاً نهاراً في حضور ذهني دائم تجاه الجسد.",
  "300": "تلامذة غوتاما بوذا يستيقظون دائماً من النوم، وذهنهم ليلاً نهاراً يجد السرور دائماً في عدم الأذى وفي تنمية الطيبة المحبة والرأفة.",
  "301": "تلامذة غوتاما بوذا يستيقظون دائماً من النوم، وذهنهم ليلاً نهاراً يجد السرور دائماً في التدريب الذهني.",
  "302": "من الصعب أن تُصبح راهباً، من الصعب أن تكون سعيداً وأنت تُمارس التدريبات التي يقوم بها الراهب. الحياة المنزلية صعبة، والعيش مع ذوي الطبائع المختلفة مؤلم، والمسافر في السمسارا يتعرض دائماً للمعاناة. لذلك، لا تكن من المسافرين في السمسارا، ولا مِمّن يتعرضون المرة تلو الأخرى للمعاناة.",
  "303": "من امتلك تقوى سليمة وكان سلوكه سليماً، وامتلك الصيت والثروة أيضاً، يُجلّه الناس حيث يكون.",
  "304": "الأخيار منيرون مثل جبال الهيمالايا [المكسوة بالثلج]، نراهم حتى من بعيد. والأشرار مثل الأسهم التي تُطلق ليلاً لا تمكن رؤيتها.",
  "305": "من يجلس وحيداً وينام وحيداً ويمشي وحيداً وهو مثابر في ممارساته وتدريباته، ويُروّض نفسه بنفسه، لا بدّ أن يجد سروراً في حياة الغابة.",
  "chap22": "عَوالم المُعاناة القُصوى",
  "306": "مَن يَقومُ بالاتّهامات الكاذبة يُعاد ميلاده في المُعاناة القُصوى Niraya. كذلك مَن يقوم بالأمور الهدّامة، ويقول: لم أفعل ذلك، يُعاد ميلاده أيضاً في عالم المُعاناة القُصوى. وكلاهما كفاعل الأمور الهدّامة، يُعاني بنفس الدرجة في وجوده التالي بعد موته.",
  "307": "كثيرون ممّن يرتدون رداء الرهبنة الأصفر حتى رقابهم، لديهم ميول هدّامة وشريرة، وغير منضبطين في فكرهم وكلامهم وأفعالهم؛ فيُعاد ميلادهم في عالم المُعاناة القُصوى بسبب أفعالهم الشريرة.",
  "308": "من الأفضل للإنسان أن يتناول كُتلةً من الحديد الساخن والمحترق كالجمر بدلاً من أن يأكل طعام الهبات الذي يُقدّمه الناس، إذا كان هذا المرء بلا أخلاق، وغير منضبط في فكره وكلامه وأفعاله.",
  "309": "أربعُ عواقب تحلّ على من لا يتمتّع بالانتباه واليقظة، ومَن يُسيء في سلوكه الجنسي مع زوجة رجل آخر: يُهدّم ما قام ببنائه، ويُواجه الازدراء والاحتقار، ويُعاني مشاكل في النوم، ثم ينتهي به الأمر في عالم المُعاناة القُصوى.",
  "310": "هذا المرء يُهدّم ما قام ببنائه، و يُعادُ ميلاده في عوالم المُعاناة القُصوى. فاستمتاع الرّجل الخائف مع المرأة الخائفة قصيرُ الأجل، ويتبعه عذابٌ من المَلِك. لذلك على الرّجل ألا يُسيء في سلوكه الجنسي مع زوجة رجل آخر.",
  "311": "مثل العُشبة التي إذا أُمسكت بشكل خاطئ، تجرحُ اليد التي تُمسكها. كذلك إذا كانت حياة الراهب أو الزاهد فاسدة، فإنّها تجرّه إلى عالم المُعاناة القُصوى.",
  "312": "لا يعود بالنّفع على الرّاهب أيّ فعل يقوم به بلا مُبالاة، أو أيّ فعل خسيس، أو أيّ سلوك مُريب.",
  "313": "إذا كان هناك ما ينبغي عليك القيام به فأنقذه، وقُم به بعزيمة ونشاط؛ لأنّ الحياة المُهملة والبليدة للراهب أو الزاهد تُثير غُبار السّموم الذهنية بدلاً من أن تُزيلها.",
  "314": "من الأفضل ألا تقوم بفعل شرير، لأنّ ذلك يجلب الندم. ومن الأفضل لك أن تقوم بعمل خير لا تندم على فعله.",
  "315": "مثل البلدة المُجاورة للحدود والمُحصّنة من الداخل والخارج، هكذا حصّن نفسك، ولا تترك الفرصة المُلائمة تمرّ. فأولئك الذين تفوتهم هذه اللحظة يُبتلون بالحزن والهمّ عندما يسقطون في عالم المُعاناة القُصوى.",
  "316": "من يخجلون مِمّا لا ينبغي الخجل منه، ولا يستخون مِمّا ينبغي الخجل منه، ويحملون رؤى خاطئة، يُعاد ميلادهم في حالة أسوأ.",
  "317": "من يرون الخطر فيما ليس خطرًا، ولا يرون الخطر فيما هو خطرٌ، ويحملون رؤى خاطئة، يُعاد ميلادهم في حالة أسوأ من الوجود.",
  "318": "من يرون الخطأ فيما ليس خطأً، ولا يرون الخطأ فيما هو خطأ، ويحملون الرؤى الخاطئة، يُعاد ميلادهم في حالة أسوأ من الوجود.",
  "319": "من يُدرك من الكائنات ما هو خاطئ على أنّه خاطئ، ومَن يعرف ما هو صحيح على أنّه صحيح، ويحمل الرؤى الصحيحة، يُعاد ميلاده في عالم أفضل من الوجود.",
  "chap23": "الفيل",
  "320": "مثلما يتحمل الفيلُ السّهام التي ترميها الأقواسُ في ساحة المعركة، كذلك أنا سوف أتحمّل الكلام المؤذي. ألا إنّ سلوك الكثير من الناس سيئ.",
  "321": "لا يُقاد إلى ساحات المعركة سوى الخيول والفيلة المدرّبة، والملكُ لا يعتلي إلا الفيلة والخيول المدرّبة. والأكثرُ نُبلاً من بين النّاس هم الذين رَوّضوا أنفسهم، والذين يتحمّلون الإساءة بصبر.",
  "322": "عندما تُدرّب البغال والخيول الأصيلة والفيلة العظيمة من بلاد السّند تُصبح رائعة، لكنّ الإنسان الذي رَوّض نفسه أكثرُ رَوْعة.",
  "323": "ليس بأي وسيلة تنقُّلٍ يُمكن للمرء أن ينال النيرفانا. لكن من خلال ترويض النّفس بعمق، يُمكن لمَن روّض نفسه أن ينال النيرفانا.",
  "324": "الفيل الذي يُدعى دانابالا Dhanapāla في اهتياج، غيرُ مروّض. وهو في الأسر لا يأكل حتّى لُقمة واحدة، فهو في حنينٍ إلى غابته.",
  "325": "من يُعاني من الكسل والشراهة وكثرة النّوم والاستلقاء والتقلّب في الفراش، مِثْلُه مثلُ الخنزير الكبير، الذي يطعَمُ الحبوب. كذلك الإنسان البليد الذي يُولَد في الرّحِم المرّة تلو الأخرى.",
  "326": "في الماضي كان هذا الذّهن يجول كيفما شاء وحيثما شاء، وراء متَعه الخاصّة. أمّا الآن فسوف أسيطر على ذهني بحكمة مثلما يستخدم سائق الفيل المهماز ليقود فيلاً هائجاً.",
  "327": "استدعِ السُّرور في الانتباه واليقظة، وحصّن ذهنك جيّدًا. كالفيل العالق في الوحل يجُرّ نفسه خارجه، اسحب نفسك من وَحْلِ التّعاسة.",
  "328": "إذا وجدت صديقًا حكيمًا، ورفيقًا يتحلّى بالسّلوك السّليم وقد تغلّب على جميع العوائق، فرافقه بسرور وذهن حاضر.",
  "329": "إذا لم يجد المرء رفيقًا حكيمًا يتحلّى بالسّلوك السّليم، وَجَبَ عليه أن يعيش وحيدًا مثل الملك الذي تخلّى عن البلد التي تمّ غزؤها، ومثل فيل Mātanga الذي يجول وحيدًا في الغابة.",
  "330": "من الأفضل أن تعيش وحيدًا، فلا صُحبة مع الأحمق. وعلى المرء أن يجول وحيدًا وألاّ يرتكب فعلاً مشيئًا، وأن يكون لديه القليلُ من المسؤوليات، مثل فيل Mātanga الذي يجول وحيدًا في الغابة.",
  "331": "من الخير أن يكون لديك أصدقاء عندما تدعو الحاجة إلى ذلك، ومن السّعادة أن ترضى بما هو موجود، ومن السّعادة أن تكون لديك فضيلةٌ تُوشك حياتُك على النّهاية، ومن السّعادة أن تتخلّص من جميع المُعاناة.",
  "332": "من الأمور السارّة في هذا العالم أن يقوم المرء بالواجب تجاه أُمّه، وأن يقوم كذلك بالواجب تجاه والده. ومن الأمور السارّة في هذا العالم أيضًا أن تخدم النُّساك والبوذات.",
  "333": "من الأمور السارّة أن تتحلّى بالفضيلة حتّى في كِبَر السنّ. ومن الأمور السارّة أن تتمتّع بتوق واعتقاد سليم لا يتزعزع. ومن الأمور السارّة أن تنال الحكمة. ومن الأمور السارّة أخيرًا ألاّ تسلك سلوكًا بطالاً.",
  "chap24": "الاشتهاء",
  "334": "في داخل المرء غير المتمتّع باليقظة والانتباه، ينمو الاشتهاء كالنباتات المتسلّقة؛ فيركضُ من ميلاد لآخر، كالقرد الذي يسعى خلف الفواكه في الغابة.",
  "335": "في هذا العالم، ينمو الأسى داخل المرء الذي غلبه عنيفُ الاشتهاء، والذي تتشبّث بالعالم، كعُشبٍ نما بكثافة.",
  "336": "في هذا العالم، يزول الأسى مِمّن تغلّب على هذا الاشتهاء العنيف - الذي يصعب التخلّص منه - مثل قطرات الندى المتساقطة عن ورقة زهرة اللوتس.",
  "337": "ولذلك سأنقل إليكم هذه التعاليم القيمة، إليكم يا من اجتمعتم هنا: اجتثّوا الاشتهاء من جذوره مثل المرء الذي يطلب الجذر العَطر، فيبحث عن جذور عشب البيرانا. لا تَدَعوا المارا تُدمّركم المرّة تلو الأخرى كما يُدمّر الماء الجاري القصب.",
  "338": "كما أنّ الشجرة ثابتةُ الجذور والسليمة تنمو حتّى بعد قطعها، كذلك الاشتهاء الكامن الذي لم يُجتثّ من جذوره، تنشأ المعاناة منه المرّة تلو الأخرى.",
  "339": "المرء ذو الرؤى الخاطئة، الذي تتدفّق بداخله تيارات الاشتهاء الستّة والثلاثون التي تقودها الرغبة الشديدة، سينجرف بسبب ذلك الرغبة الشديدة.",
  "340": "تندفع نوازعُ الاشتهاء نحو الأشياء المحسوسة، فتنشأ شجرة الاشتهاء المتسلّقة، وتُثبت نفسها. فعندما ترى تلك الشجرة المتسلّقة تنمو، اقطع جذورها بالحكمة.",
  "341": "تنشأ في الكائنات سعادة مشوبة بالاشتهاء. وتبقى هذه الكائنات المتعلّقة بالمتعة والساعية نحوها في دائرة الميلاد وكبر السنّ.",
  "342": "أولئك المبتلون بالاشتهاء، مُروّعون كأرنب وقع في الفخّ، مكبّلون بالقيود ويقعون في دائرة المعاناة المرة تلو الأخرى، ولزمن طويل.",
  "343": "أولئك المبتلون بالاشتهاء، مُروّعون كأرنب وقع في الفخّ. لذلك فإنّ الراهب الذي يتمنّى تحرير نفسه من الرغبة الشديدة، عليه أن يتخلّص من الاشتهاء.",
  "344": "ذلك الشخص الذي ترك حياة غابة الرغبات، وسعى في حياة التدريب، عاد مندفعًا نحوها بعد أن تحرّر منها. تعالوا وانظروا إلى ذلك الشخص الذي بعدما تحرّر عاد مندفعًا إلى تلك القيود ذاتها.",
  "345": "لا يرى ذو الحكمة أنّ الروابط المصنوعة من الحديد والخشب والقنّب روابط قويّة. فالشغف بالجواهر والأحجار الكريمة والأولاد والزوجات هي الروابط والقيود القويّة، إذ تجرّ المرء للأسفل.",
  "346": "ومع أنّها تبدو سهلة، من الصعب التحرّر منها. لكنّ ذا الحكمة يكسر هذه القيود، وينبذ المتع الحسيّة، من دون الحنين ثانية إليها.",
  "347": "الكائنات المأخوذة بالرغبات الحسّيّة تقع في تيارات الاشتهاء الذي صنعته بنفسها، مثل العنكبوت الذي يقع في الشبكة التي صنعها. لكنّ الحكيم الذي كسر قيود الاشتهاء، يمشي بعزم تاركًا المعاناة كلّها خلفه.",
  "348": "انبذ ما هو خلفك وما هو أمامك، وتخلّ عمّا بينهما، واسمُ إلى ما فوق الوجود، وبذهن متحرّر من كلّ شيء؛ وهكذا لن تخضع لدائرة إعادة الميلاد والموت.",
  "349": "الشخص الذي تشتّته الأفكار والرغبة الشديدة الشديدة، والذي يُطيل تأمّل الأشياء الممتعة، يزيد فيه الاشتهاء أكثر فأكثر، فيزيد حقًّا من حدّة أسره.",
  "350": "لكنّ من يجد السرور في تهدئة أفكاره، والذي يتمتّع بالحضور الدائم، ويتأمّل في الأمور المزعجة، سينهي المعاناة فيه. مِثْلُ هذا الشخص سيكسر قيود المارا.",
  "351": "ذلك الذي نال مرحلة الأرهات، متحرّرٌ من الخوف ومن الاشتهاء ومن الفساد، قد قطع أسهم الوجود، وسيكون هذا آخر ميلاد له.",
  "352": "من تحرّر من الاشتهاء ومن التعلّق، والماهر في معرفة تفاصيل دلالات كلمات التعاليم، والذي يعرف مجموعات الأحرف وتتابعها، ومَن عاش آخر ميلاد له، يُطلق عليه بالفعل 'صاحب حكمة عظيمة، وشخص عظيم'.",
  "353": "لقد تغلّبتُ على كلّ شيء، لقد عرفتُ كلّ شيء، ولستُ متعلّقًا بأيّ شيء. فقد تخلّيت عن كلّ شيء، وتحرّرتُ من كلّ الفساد بعدما تخلّصتُ من الاشتهاء. وبعدما استوعبتُ الحقائق النبيلة الأربع بنفسي مباشرة، من سأشير إليه كمعلّم لي؟",
  "354": "هدية الدارما تفوق كلّ الهدايا، وطَعْم الدارما يفوق كلّ الأطعمة، والسرور في الدارما يفوق كلّ أشكال السرور، وإزالة الاشتهاء يهزم جميع أشكال المعاناة.",
  "355": "الثراء يُدمّر الأحمق، لكنّه لا يُدمّر مَن يسعون نحو الشاطئ البعيد أي النيرفانا. فباشتهاء الأحمق للثروة يُدمّر نفسه ويُدمّر الآخرين.",
  "356": "يُتلف العُشبُ الحقول، والشغف يُفسد جميع الكائنات. لذلك فإنّ تقديم العطايا لِمَن تحرّروا من الرغبة الشديدة والشغف يجلب النفع الكثير.",
  "357": "يُتلف العُشبُ الحقول، والكُره يُفسد جميع الكائنات. لذلك فإنّ تقديم العطايا لِمَن تحرّروا من الكره يجلب النفع الكثير.",
  "358": "يُتلف العُشبُ الحقول، والوهم يُفسد جميع الكائنات. لذلك فإنّ تقديم العطايا لِمَن تحرّروا من الوهم يجلب النفع الكثير.",
  "359": "يُتلف العُشبُ الحقول، والاشتهاء يُفسد جميع الكائنات. لذلك فإنّ تقديم العطايا لِمَن تحرّروا من الاشتهاء يجلب النفع الكثير.",
  "chap25": "الرّاهب",
  "360": "التحكّم في الحواسّ، من بصرٍ وسمعٍ وشمٍّ وكلام، خيرٌ.",
  "361": "الانضباط في الجسد خيرٌ، ومن الخير الانضباط في الكلام، وفي الذّهن، في كلّ مكان. الرّاهب المنضبط في جميع حواسّه متحرر من كلّ معاناة.",
  "362": "من يتحكّم في يده، ويتحكّم في قدمه، ويتحكّم في كلامه، وله كاملُ السيطرة على نفسه، ويجدُ السُّرور الداخليّ في حالة الصامادي وفي خلوته راضيًا، يُسمّى راهبًا.",
  "363": "الرّاهب الذي يتحكّم في فمه، والمعتدل في كلامه، والمتّزن، والذي يشرح معاني الدّارما ونصوصها، حلوةٌ هي كلماتُه.",
  "364": "الرّاهب الذي يجد السرور في الدّارما، ومَن يتأمّل ويبحثُ في الدّارما، ويتذكّر الدّارما دائمًا، لن يحيد عنها أبدًا.",
  "365": "على الإنسان ألاّ يستخفّ أو يزدري ما ناله، وعليه ألاّ يحسد الآخرين على مكاسبهم. فالرّاهب الذي يحسد الآخرين لا يُمكنه بلوغ حالة الصامادي.",
  "366": "مع أنّ الراهب لا يحصل إلاّ على القليل، فإنه إذا لم يأسف على هذا القليل الذي حصل عليه، فكائنات الديفا ستثني حقًّا على من يسلك حياةً نقيّة، غير بليدة.",
  "367": "من لا ينظر للأمور الماديّة على أنَّها 'أنا ولي'، ومَن لا يتحسّر على تحلّل الذّهن والجسد، يُسمّى بالفعل الرّاهب.",
  "368": "إنَّ الراهب الذي يعيش في مُمارسة الطيبة المُحبّة، والذي يثق بتعاليم بوذا، سيُدرك حالة السلام والسّكينة.",
  "369": "أيُّها الراهبُ أخرج الماء من هذا القارب، وعند ذلك سيسير بانسياب، وبعد أن تتخلّص من الرغبة الشديدة والكُره ستُدرك النيرفانا.",
  "370": "تخلّص من الخمسة: (القيود الدنيا الخمسة: 1. وجهات النّظر حول ما يتعلّق بالنّفس أو ما تملكه النّفس 2. الشكّ 3. التشبّث 4. الاشتهاء الحسّي 5. الكُره)، وتخلّ عن الخمسة (القيود الخمسة: 1. التعلّق بالظواهر الملموسة 2. التعلّق بالظواهر غير الملموسة 3. التكبّر 4. الاضطراب 5. الجهل)، ونَمِّ الخمس (مَلَكات الانضباط: الثّقة، السّليم، بذل الجُهد السّليم، الحضور الذّهني، وحالة الصامادي والحكمة والبصيرة)، فالراهب الذي حَرّر نفسه من القيود الخمسة يُسمّى (من عَبَر الفيضان أي السمسارا).",
  "371": "تأمّل أيُّها الراهبُ ولا تكن غافلاً أو شارد الذّهن، ولا تَدَع ذهنك يضيع في المتَع الحسّيّة. لا تفقد حضورك الذهنيّ، فتبلع كُتلة الحديد المُشتعلة؛ فتصرخ وأنت تحترق في عالم المعاناة القصوى: 'هذه معاناة'.",
  "372": "لا يُمكن أن يصل الإنسان إلى حالة الصامادي وهو يفتقر إلى الحكمة. ولا يُمكن أن تُوجَد الحكمة فيمن لا يتدرّب على التأمّل. من يحظى بحالة الصامادي والحكمة هو بالفعل قريبٌ من النيرفانا.",
  "373": "الرّاهب الذي يختلي، والذي يتمتّع بذهن هادئ، والذي يُدرك الدّارما بجلاء، يعيش متعة تفوق متعة الناس.",
  "374": "في كلّ مرّة يتفكّر الراهب وينبحث المرء في نشوء مكوّنات الأشياء والكائنات وزوالها إشارةً إلى تأمّل البصيرة، يجد السعادة والنشوة في ذلك. وهذا هو الطريق للنيرفانا - لمَن يملك الحكمة.",
  "375": "بالنسبة إلى الراهب هذه هي التعاليم الأساسيّة: ضبط الحواسّ، والرّضى، وضبط النّفس بناءً على المبادئ الأساسيّة.",
  "376": "كُن على صلة بالأصدقاء الروحانيّين الأخيار، الذين يتمتّعون بالنشاط، وعيشهم نقيّ. كُن حسنَ الضّيافة وذوذا، واسلك بصواب. هكذا، ومع تكرار مشاعر السعادة الغامرة، ستنتهي المعاناة.",
  "377": "أيُّها الرّاهب! مثلما يتخلّى نبات الياسمين عن أزهاره الذابلة، تخلّ أنت أيضًا عن الرغبة الشديدة والكره.",
  "378": "الرّاهب الذي يتمتّع بهدوء في الجسد، وهدوء في الكلام، وهدوء في الذّهن، ويتمتّع بالتّركيز وقد تخلّص من متع العالم، يُطلق عليه 'من تمتّع بالسّكينة'.",
  "379": "أيُّها الرّاهبُ حُضّ نفسك بنفسك، واختبر نفسك. فإذا حصّنت نفسك هكذا وكنت حاضرًا، ستعيش في سعادة.",
  "380": "المرء هو ملجأ نفسه ومُخلص نفسه. الإنسان بالفعل ملاذُ نفسه، لذلك اعتنِ بنفسك مثل تاجر الخيول الذي يعتني بالخيل الأصيلة.",
  "381": "إنّ الرّاهب الذي يشعر باستمرارٍ بالسُّرور ويثق بتعاليم بوذا، سوف يُحقّق حالة السلام الداخلي، أي نهاية الحالات المشروطة.",
  "382": "حتّى الراهبُ صغير السنّ، الذي يُكرّس نفسه من أجل تعاليم بوذا، يُنير العالم مثل القمر المُنير في سماءٍ صافية، لا غُيوم فيها ولا سُحُب.",
  "chap26": "البراهمن",
  "383": "أيها البراهمن، اقطع تيار الاشتباه بعد أن اجتهدت وثابرت وتخلصت من الرغبات الحسية. أيها البراهمن، لقد عرفت زوال الأشياء المشروطة، فأنت تعلم النيرفانا.",
  "384": "عندما يصل البراهمن إلى الشاطئ البعيد خارج الثنائية، تتحطم كل القيود.",
  "385": "من ليس على هذا الشاطئ ولا على الشاطئ البعيد، ومن لا يعاني من التوتر الذهني، وكان خاليًا من القيود، أسميه البراهمن.",
  "386": "من يتدرب على التأمل، وهو خالٍ من غبار السموم الذهنية، والذي وصل إلى أسمى غاية، أسميه البراهمن.",
  "387": "تشرق الشمس في النهار، وينير القمر في الليل، وفي درعه يشرق المحارب، وفي التأمل يشرق البراهمن. لكن بوذا في تألقه ينير في كل الأوقات، في الليل وفي النهار.",
  "388": "يُسمّى المرء 'البراهمن' لأنه نبذ الشرور، ويُسمّى من يعيش باتزان ناسكًا أو زاهدًا (samana)، ويُسمّى المرء باباجتا (Papajita) لأنه تخلى عن كل ما يشين سلوكه.",
  "389": "ينبغي عدم الاعتداء على البراهمن، وينبغي على البراهمن عدم الشعور بالغضب نتيجة الاعتداء عليه. فمن المشين الاعتداء على البراهمن، لكن ما هو مشين أكثر هو شعور الغضب تجاه المعتدي.",
  "390": "بالنسبة إلى البراهمن لا شيء أفضل من أن يصون ذهنه من الأمور العزيزة عليه. ويكون مدى زوال المعاناة بحجم النيّة عن كفّ الأذى.",
  "391": "إذا لم يقم المرء بالسوء فعلاً أو قولاً أو فكرًا -من ضبط نفسه ضمن هذه الثلاثة- أسميه البراهمن.",
  "392": "إذا تعلم إنسان تعاليم بوذا من شخص ما، وجب أن يُقدّم له الاحترام والتبجيل، مثلما يُبجّل البراهما نار القربان.",
  "393": "لا يُصبح المرء براهمن بشعره المجدول أو لنسبه أو أصله، أو لطبقته الاجتماعية. من يُدرك الحقيقة والدارما فقط يُعتبر نقيًا، وهو من أسميه البراهمن.",
  "394": "أيها الأحمق! ما نفع شعرك الطويل المجدول؟ وما نفع ما ترتديه من جلد؟ وفي داخلك غابة من الشرور، تُهملها وتكتفي بتنقية ذاتك من الخارج.",
  "395": "من يرتدي الأثواب من قطع القماش الخرقة، وهو هزيل وقد بدت عروقه من تحت جلده، ومن يتأمل وحيدًا في الغابة، أسميه البراهمن.",
  "396": "لا أطلق على المرء البراهمن، فقط لأنه وُلد من رحم أنثى من طبقة البراهما، إذا كان متغطرسًا ومتكبرًا. من خلا من السموم الذهنية والتعلق، أسميه البراهمن.",
  "397": "من كسر كل القيود وخلا من الخوف، من تجاوز القيود وخلا من التعلق، أسميه البراهمن.",
  "398": "من قطع الحبل والرباط وفتح القفل، ومن استيقظ واستنار، أسميه البراهمن.",
  "399": "من يتحمل الإساءة والضرب والحبس بضبر ودون كره، قُوَّتُه الصبر وجيشُه القوة، أسميه البراهمن.",
  "400": "من لا يغضب، وصاحب السلوك السليم، ومن يتمتع بالفضيلة ويخلو من الكِبْر، والمنضبط، ومن جسده الحالي آخر جسد له، أسميه البراهمن.",
  "401": "من لا يتشبث بالمتع الحسيّة، مثل قطرات الماء التي لا تتشبث بأوراق زهرة اللوتس، أو مثل حبة الخردل التي لا تعلق بطرف الإبرة، أسميه البراهمن.",
  "402": "من يُدرك، حتى في هذا الوجود، نهاية معاناته، والذي يُلقي العبء جانبًا، والذي يخلو من التعلق، أسميه البراهمن.",
  "403": "من يتمتع بالحكمة العميقة، والماهر في مساره الروحاني وفي غير ذلك، والذي نال أسمى الغايات، أسميه البراهمن.",
  "404": "من لا يرتبط بأصحابة المنازل والبيوت، أو ذاك الذي ترك البيوت أو المأوى، والذي يخلو من الرغبات الحسيّة، وليس لديه إلا القليل من الرغبات، أسميه البراهمن.",
  "405": "من ألقى جانبًا استخدام القوة ضدّ جميع الكائنات، سواءً الأقوياء أم الضعفاء، والذي لا يقتل ولا يجعل الآخرين يتسببون بالقتل، أسميه البراهمن.",
  "406": "من لا يتصرّف بعدوانية بين المعتدين، ومن يتصف بالسلام مع أولئك الذين يحملون السلاح، ومن لا يتعلّق بالأشياء التي يتعلّق بها الآخرون، أسميه البراهمن.",
  "407": "من تخلص من الاشتباه والكُره والغرور والانتقاص من شأن الآخرين، مثلما تسقط حبّة الخردل من طرف الإبرة، أسميه البراهمن.",
  "408": "من يتحدّث بلُطف من دون قسوة ويقول كلامًا حقيقيًا، ومن لا يؤذي أحدًا بكلامه، أسميه البراهمن.",
  "409": "من لا يأخذ شيئًا لم يُعطه في هذا العالم، سواءً صغر أم كبر أم طال أم قصر، سواءً كان حسنًا أم قبيحًا، أسميه البراهمن.",
  "410": "الذي ليس فيه رغبةٌ لا في هذا العالم ولا فيما يليه، ومن خلا من التعلّق، أسميه البراهمن.",
  "411": "الذي ليس فيه شهواتٌ، ومن لا يُعاني من الشكّ من خلال المعرفة، ومَن أدرك النيرفانا، أسميه البراهمن.",
  "412": "الذي ترفّع في هذا العالم عن التعلّق بأمور الخير والشرّ، والنقيّ الذي لا يشعر بالأسى، أسميه البراهمن.",
  "413": "الذي مثله مثل القمر، نقيّ وواضح وبلا فساد، ومن تخلّص من السرور بهذا الوجود، أسميه البراهمن.",
  "414": "الذي تغلّب على هذه الطريق الصعبة، طريق السمسارا والوهم، والذي عبر إلى الشاطئ البعيد، والذي يتدرّب على التأمل، والذي يحيا في سلام تامّ لأنه لا يتشبث بشيء، أسميه البراهمن.",
  "415": "من تخلّى في هذا العالم عن المتع الحسّية، واتخذ التجوال بدلاً من حياة المنازل، والذي تخلّص من الشهوات الحسّية والوجود الحالي، أسميه البراهمن.",
  "416": "من تخلّى في هذا العالم عن الاشتباه، واتخذ التجوال بدلاً من حياة المنازل، والذي تخلّص من الاشتباه والوجود الحالي، أسميه البراهمن.",
  "417": "من تخلّى عن التعلّق بقيود حياة البشر، وسما فوق التعلق بحياة كائنات الديفا، ومن تخلّى عن كل القيود، أسميه البراهمن.",
  "418": "من تخلّى عن السرور وضدّه، وقد انطفأ فيه الرغبة الشديدة وغزا العالم، هذا البطل أسميه البراهمن.",
  "419": "من يعرفُ كلّ تفاصيل موت الكائنات وإعادة ميلادها، والذي خلا من التعلّق، وذو الحظّ، والمستنيرُ، أسميه البراهمن.",
  "420": "هذا الذي لا يعلمُ أحدٌ من الكائنات، سواءً الديفا أم الغندابا أم الناس إلى أين منتهاه، والذي تخلّص من السموم الأخلاقية، أسميه البراهمن.",
  "421": "مَن لا يتعلق بأي شيء في الماضي أو الحاضر أو المستقبل، ومن خلا من الجشع، أسميه البراهمن.",
  "422": "هذا المحارب كالثور، هذا البطل والحكيم والذي يخلو من الرغبات ومن كلّ ما يتحرّك في داخله من انفعالات، والذي نقّى نفسه من كلّ الفساد، والمستنير، أسميه البراهمن.",
  "423": "مَن يعرفُ كلّ الحيوات السابقة له، ومن يرى عوالم التعاسة وعوالم البهجة، ومَن أنهى دائرة إعادة الميلاد بالنسبة إليه، هو حكيمٌ أتمّ المعرفة العليا، وأتمّ كلّ ما يُمكن إتمامه، وأسميه البراهمن."
};
